/**
 * Formateador de resultados de inbox
 */
const emails = $input.all();
const classifierData = $('📧 Email Action Classifier').first().json;

if (emails.length === 0) {
  return {
    json: {
      action: 'check_inbox',
      success: true,
      emailCount: 0,
      message: '📭 No tienes correos sin leer. ¡Inbox Zero!',
      data: [],
      originalQuery: classifierData.originalQuery
    }
  };
}

const formattedEmails = emails.map((email, index) => {
  const e = email.json;
  return {
    index: index + 1,
    id: e.id,
    from: e.from?.emailAddress || e.from || 'Desconocido',
    fromName: e.from?.name || '',
    subject: e.subject || '(Sin asunto)',
    snippet: (e.snippet || '').substring(0, 100) + '...',
    date: e.date || e.internalDate,
    isUnread: e.labelIds?.includes('UNREAD') || false,
    isImportant: e.labelIds?.includes('IMPORTANT') || false,
    isStarred: e.labelIds?.includes('STARRED') || false,
    hasAttachments: e.payload?.parts?.some(p => p.filename) || false
  };
});

// Construir mensaje para XUS
let messageLines = [`📬 **${emails.length} correo${emails.length > 1 ? 's' : ''} sin leer:**\n`];

formattedEmails.forEach(email => {
  const flags = [];
  if (email.isImportant) flags.push('⭐');
  if (email.hasAttachments) flags.push('📎');

  messageLines.push(
    `${email.index}. **${email.fromName || email.from}**${flags.length ? ' ' + flags.join('') : ''}\n` +
    `   📋 _${email.subject}_\n` +
    `   💬 ${email.snippet}`
  );
});

return {
  json: {
    action: 'check_inbox',
    success: true,
    emailCount: emails.length,
    message: messageLines.join('\n'),
    data: formattedEmails,
    originalQuery: classifierData.originalQuery
  }
};

/**
 * Formateador de resultados de búsqueda
 */
const emails = $input.all();
const classifierData = $('📧 Email Action Classifier').first().json;
const searchTerm = classifierData.emailParams.searchTerm || classifierData.emailParams.personName || 'tu búsqueda';

if (emails.length === 0) {
  return {
    json: {
      action: 'search',
      success: true,
      emailCount: 0,
      message: `🔍 No encontré correos que coincidan con "${searchTerm}".`,
      data: [],
      searchTerm: searchTerm,
      originalQuery: classifierData.originalQuery
    }
  };
}

const formattedEmails = emails.map((email, index) => {
  const e = email.json;
  return {
    index: index + 1,
    id: e.id,
    from: e.from?.emailAddress || e.from || 'Desconocido',
    fromName: e.from?.name || '',
    subject: e.subject || '(Sin asunto)',
    snippet: (e.snippet || '').substring(0, 100) + '...',
    date: e.date || e.internalDate
  };
});

let messageLines = [`🔍 **${emails.length} resultado${emails.length > 1 ? 's' : ''} para "${searchTerm}":**\n`];

formattedEmails.slice(0, 5).forEach(email => {
  messageLines.push(
    `${email.index}. **${email.fromName || email.from}**\n` +
    `   📋 _${email.subject}_\n` +
    `   💬 ${email.snippet}`
  );
});

if (emails.length > 5) {
  messageLines.push(`\n... y ${emails.length - 5} más.`);
}

return {
  json: {
    action: 'search',
    success: true,
    emailCount: emails.length,
    message: messageLines.join('\n'),
    data: formattedEmails,
    searchTerm: searchTerm,
    originalQuery: classifierData.originalQuery
  }
};

/**
 * Formateador de lectura de email individual
 */
const emails = $input.all();
const classifierData = $('📧 Email Action Classifier').first().json;

if (emails.length === 0) {
  return {
    json: {
      action: 'read',
      success: false,
      message: '❌ No pude encontrar el correo solicitado.',
      data: null,
      originalQuery: classifierData.originalQuery
    }
  };
}

const e = emails[0].json;

// Extraer el cuerpo del mensaje
let body = e.snippet || '';
if (e.payload?.body?.data) {
  try {
    body = Buffer.from(e.payload.body.data, 'base64').toString('utf-8');
  } catch (err) {
    body = e.snippet || '';
  }
}

// Limpiar HTML básico
body = body.replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();

const emailData = {
  id: e.id,
  from: e.from?.emailAddress || e.from || 'Desconocido',
  fromName: e.from?.name || '',
  to: e.to || '',
  subject: e.subject || '(Sin asunto)',
  date: e.date || e.internalDate,
  body: body.substring(0, 1500), // Limitar longitud
  isUnread: e.labelIds?.includes('UNREAD') || false,
  hasAttachments: e.payload?.parts?.some(p => p.filename) || false,
  attachments: e.payload?.parts?.filter(p => p.filename).map(p => p.filename) || []
};

let message = `📧 **Correo de ${emailData.fromName || emailData.from}**\n\n`;
message += `📋 **Asunto:** ${emailData.subject}\n`;
message += `📅 **Fecha:** ${emailData.date}\n`;
if (emailData.hasAttachments) {
  message += `📎 **Adjuntos:** ${emailData.attachments.join(', ')}\n`;
}
message += `\n---\n\n${emailData.body}`;

return {
  json: {
    action: 'read',
    success: true,
    message: message,
    data: emailData,
    originalQuery: classifierData.originalQuery
  }
};

/**
 * Formateador de etiquetas
 */
const labels = $input.all();
const classifierData = $('📧 Email Action Classifier').first().json;

const formattedLabels = labels.map(l => {
  const label = l.json;
  return {
    id: label.id,
    name: label.name,
    type: label.type,
    messagesTotal: label.messagesTotal || 0,
    messagesUnread: label.messagesUnread || 0
  };
}).filter(l => l.type !== 'system' || ['INBOX', 'SENT', 'DRAFT', 'SPAM', 'TRASH', 'STARRED', 'IMPORTANT'].includes(l.id));

let message = `🏷️ **Tus etiquetas de Gmail:**\n\n`;

// Separar sistema de personalizadas
const systemLabels = formattedLabels.filter(l => l.type === 'system');
const userLabels = formattedLabels.filter(l => l.type === 'user');

message += `**📁 Carpetas del sistema:**\n`;
systemLabels.forEach(l => {
  message += `• ${l.name} (${l.messagesTotal} correos, ${l.messagesUnread} sin leer)\n`;
});

if (userLabels.length > 0) {
  message += `\n**🏷️ Etiquetas personalizadas:**\n`;
  userLabels.forEach(l => {
    message += `• ${l.name} (${l.messagesTotal})\n`;
  });
}

return {
  json: {
    action: 'get_labels',
    success: true,
    message: message,
    data: formattedLabels,
    originalQuery: classifierData.originalQuery
  }
};

/**
 * Preparar datos para el resumen
 */
const emails = $input.all();
const classifierData = $('📧 Email Action Classifier').first().json;

if (emails.length === 0) {
  return {
    json: {
      emailList: 'No hay correos en el inbox.',
      emailCount: 0,
      originalQuery: classifierData.originalQuery
    }
  };
}

const emailList = emails.map((email, index) => {
  const e = email.json;
  return `${index + 1}. De: ${e.from?.name || e.from || 'Desconocido'} <${e.from?.emailAddress || ''}>\n   Asunto: ${e.subject || '(Sin asunto)'}\n   Preview: ${(e.snippet || '').substring(0, 150)}\n   Fecha: ${e.date || 'Desconocida'}\n   ¿Leído?: ${e.labelIds?.includes('UNREAD') ? 'No' : 'Sí'}`;
}).join('\n\n');

return {
  json: {
    emailList: emailList,
    emailCount: emails.length,
    originalQuery: classifierData.originalQuery
  }
};

/**
 * Formatear resultado del resumen
 */
const summaryResult = $input.first().json;
const classifierData = $('📧 Email Action Classifier').first().json;
const emailCount = $('📋 Prepare for Summary').first().json.emailCount;

let message = `📊 **Resumen de tu Inbox** (${emailCount} correos)\n\n`;
message += summaryResult.output || summaryResult.text || 'No pude generar el resumen.';

return {
  json: {
    action: 'summary',
    success: true,
    message: message,
    data: {
      emailCount: emailCount,
      summary: summaryResult.output || summaryResult.text
    },
    originalQuery: classifierData.originalQuery
  }
};

/**
 * ═══════════════════════════════════════════════════════════════════════════════
 *   XUS NEURAL ARCHITECT v15.0 — UNIFIED EMAIL PROCESSOR
 * ═══════════════════════════════════════════════════════════════════════════════
 */

const OPERATOR_CONFIG = {
    email: "santi21435@gmail.com",
    name: "Santiago Rubio",
    firstName: "Santiago",
    title: "Founder & CEO",
    company: "NEXUS VNXS AGENCY",
    tagline: "Personal Brand Systems",
    mission: "Operación 2026",

    aliases: [
        "santiago", "santi", "rubio", "yo", "mí", "mi", "me", "a mí", "para mí",
        "mi correo", "mi email", "envíamelo", "enviamelo", "mándamelo", "mandamelo",
        "envíame", "enviame", "mándame", "mandame", "el jefe", "el boss"
    ]
};

const inputData = $input.first().json;
let aiData = {};

// Parsear respuesta de la IA
function extractJSON(text) {
    if (!text || typeof text !== 'string') return null;
    let clean = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    const jsonMatch = clean.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
        try { return JSON.parse(jsonMatch[0]); } catch (e) { return null; }
    }
    return null;
}

// Procesar output de IA
if (typeof inputData === 'object' && (inputData.to || inputData.subject || inputData.body)) {
    aiData = inputData;
} else if (inputData.text) {
    aiData = extractJSON(inputData.text) || { body: inputData.text };
} else if (inputData.output) {
    aiData = extractJSON(inputData.output) || { body: inputData.output };
} else {
    aiData = { to: OPERATOR_CONFIG.email, subject: "Nota Automática", body: "Email generado por XUS." };
}

// Resolver destinatario
function isOperatorAlias(text) {
    if (!text) return false;
    const normalized = text.toLowerCase().trim();
    return OPERATOR_CONFIG.aliases.some(alias => normalized.includes(alias));
}

let classifierData = {};
try { classifierData = $('📧 Email Action Classifier').first().json; } catch(e) {}
const msgOriginal = (classifierData.originalQuery || "").toLowerCase();

let destinatario = (aiData.to || "").trim().replace(/['"<>]/g, '');
if (isOperatorAlias(destinatario) || isOperatorAlias(msgOriginal) || !destinatario.includes('@')) {
    destinatario = OPERATOR_CONFIG.email;
}

const isForOperator = destinatario === OPERATOR_CONFIG.email;
const emailAction = classifierData.emailAction || 'send';
const target = emailAction === 'draft' ? 'draft' : 'send';

// Procesar contenido
let asunto = (aiData.subject || "").trim() || (isForOperator ? "Nota Personal" : "Comunicación");
let cuerpoTexto = aiData.body || aiData.content || aiData.message || "Sin contenido.";

// Generar HTML (simplificado)
const cuerpoHtml = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="font-family: -apple-system, sans-serif; padding: 20px; max-width: 600px; margin: 0 auto;">
<div style="border-left: 4px solid #667eea; padding-left: 20px;">
<p style="font-size: 11px; color: #666; text-transform: uppercase; letter-spacing: 1px;">📧 ${isForOperator ? 'Nota Personal' : 'Comunicación Estratégica'}</p>
<div style="color: #1a1a1a; font-size: 15px; line-height: 1.8;">
${cuerpoTexto.replace(/\n\n/g, '</p><p>').replace(/\n/g, '<br>')}
</div>
<hr style="border: none; border-top: 1px solid #eee; margin: 25px 0;">
<p style="font-size: 12px; color: #666;"><strong>${OPERATOR_CONFIG.name}</strong><br>${OPERATOR_CONFIG.title} · ${OPERATOR_CONFIG.company}</p>
</div>
</body></html>`;

return {
    json: {
        to: destinatario,
        subject: asunto,
        body: cuerpoTexto,
        html: cuerpoHtml,
        target: target,
        isForOperator: isForOperator,
        hasAttachment: false,
        chatId: classifierData.chatId || '',
        originalQuery: msgOriginal
    }
};

/**
 * Formatear resultado de envío/borrador con contexto de Nova.
 */
const result = $input.first().json;
const architectData = $('🏗️ Neural Architect').first().json;
let novaEvaluation = null;
try {
  novaEvaluation = $('🛡️ Nova Evaluate Send').first().json.nova || null;
} catch (error) {
  novaEvaluation = null;
}

const action = architectData.target === 'draft' ? 'draft' : 'send';
const actionEmoji = action === 'draft' ? '📝' : '🚀';
const actionText = action === 'draft' ? 'BORRADOR GUARDADO' : 'EMAIL ENVIADO';

let message = `${actionEmoji} **${actionText}**\n\n`;
message += `📧 **Para:** ${architectData.to}${architectData.isForOperator ? ' (Tú)' : ''}\n`;
message += `📋 **Asunto:** _${architectData.subject}_\n`;

if (action === 'send') {
  message += `\n✅ El correo fue enviado exitosamente.`;
  if (novaEvaluation?.decision?.action) {
    message += `\n🛡️ Nova: ${novaEvaluation.decision.action} · riesgo ${novaEvaluation.risk_score}`;
  }
} else {
  message += `\n💾 Guardado en borradores. Puedes editarlo en Gmail.`;
}

return {
  json: {
    action: action,
    success: true,
    message: message,
    data: {
      to: architectData.to,
      subject: architectData.subject,
      isForOperator: architectData.isForOperator,
      gmailResponse: result,
      nova: novaEvaluation,
    },
    originalQuery: architectData.originalQuery
  }
};

/**
 * Placeholder para reply - necesita más contexto
 */
const classifierData = $('📧 Email Action Classifier').first().json;

return {
  json: {
    action: 'reply',
    success: false,
    message: '↩️ **Para responder un correo necesito más contexto.**\n\nOpciones:\n1. "Responde al último correo de [persona]"\n2. "Responde al correo sobre [tema]"\n3. Primero revisa el inbox y luego indica cuál responder.',
    data: null,
    originalQuery: classifierData.originalQuery
  }
};

/**
 * Placeholder para delete - necesita confirmación
 */
const classifierData = $('📧 Email Action Classifier').first().json;

return {
  json: {
    action: 'delete',
    success: false,
    message: '🗑️ **Para eliminar correos necesito confirmación.**\n\n¿Cuál correo quieres eliminar?\n• "Elimina el correo de [persona]"\n• "Elimina el correo sobre [tema]"\n• Primero busca el correo y luego confirma.',
    data: null,
    originalQuery: classifierData.originalQuery
  }
};

/**
 * 📤 RETURN RESPONSE — Extrae output del agent para retornar al Cerebro
 */
const agentOutput = $input.first().json;

const text = agentOutput.output 
  || agentOutput.text 
  || agentOutput.response 
  || JSON.stringify(agentOutput);

return [{
  json: {
    moduleType: 'email',
    textResponse: text,
    success: true
  }
}];

/**
 * 📋 Parse Classifier — Extrae JSON del output del agent
 */
const input = $input.first().json;
const raw = input.output || input.text || JSON.stringify(input);

let result = {};

try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    result = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  result = {
    emailAction: 'check_inbox',
    emailParams: { count: 10, unreadOnly: true },
    originalQuery: raw
  };
}

return [{
  json: {
    emailAction: result.emailAction || 'check_inbox',
    emailParams: result.emailParams || {},
    originalQuery: result.originalQuery || raw,
    classifiedAt: new Date().toISOString()
  }
}];

/**
 * Build an exact Gmail Sent query for duplicate-safe sends.
 */
const input = $input.first().json;
const rawTo = String(input.to || '').trim();
const firstRecipient = rawTo.split(',')[0].trim();
const angleMatch = firstRecipient.match(/<([^>]+)>/);
const emailMatch = firstRecipient.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
const recipient = (angleMatch?.[1] || emailMatch?.[0] || firstRecipient).trim().replace(/^"|"$/g, '');
const subject = String(input.subject || '').trim();
const escapedSubject = subject.replace(/"/g, '\"');
const queryParts = ['in:sent'];
if (recipient) queryParts.push(`to:${recipient}`);
if (subject) queryParts.push(`subject:"${escapedSubject}"`);
return [{
  json: {
    ...input,
    dedupeRecipient: recipient,
    dedupeSubject: subject,
    dedupeQuery: queryParts.join(' '),
  },
}];

/**
 * Collapse Gmail search results into one deterministic duplicate decision.
 */
const context = $('🧮 Build Gmail Dedupe Query').first().json;
const matches = $input.all()
  .map((item) => item.json || {})
  .filter((item) => item.id || item.threadId || item.snippet || (Array.isArray(item.labelIds) && item.labelIds.length));
const messageIds = [...new Set(matches.map((item) => item.id).filter(Boolean))];
const latestMatch = matches[0] || null;
return [{
  json: {
    ...context,
    duplicateCheck: {
      isDuplicate: messageIds.length > 0,
      matchCount: messageIds.length,
      matchIds: messageIds,
      latestThreadId: latestMatch?.threadId || null,
      query: context.dedupeQuery,
    },
  },
}];

/**
 * Human response for real Gmail duplicate blocks.
 */
const result = $input.first().json;
const architectData = $('🏗️ Neural Architect').first().json;
const duplicateInfo = result.duplicateCheck || {};
const novaInfo = result.nova || null;
let message = '🛑 *Envío bloqueado por duplicado real*\n\n';
message += `📧 Para: ${architectData.to}\n`;
message += `📌 Asunto: ${architectData.subject || '(sin asunto)'}\n`;
message += `🔎 Coincidencias en Gmail Sent: ${duplicateInfo.matchCount || 0}\n`;
message += '\nNo envié el correo porque Gmail confirma que ya salió uno con el mismo destinatario y asunto.';
if (novaInfo?.eval_id) {
  message += `\n🛡️ Nova registró el bloqueo: ${novaInfo.eval_id}`;
}
return [{
  json: {
    action: 'duplicate_blocked',
    success: true,
    message,
    data: {
      to: architectData.to,
      subject: architectData.subject,
      duplicateCheck: duplicateInfo,
      nova: novaInfo,
    },
    originalQuery: architectData.originalQuery,
  },
}];

/**
 * Human response when Nova does not allow the send.
 */
const result = $input.first().json;
const architectData = $('🏗️ Neural Architect').first().json;
const nova = result.nova || {};
const decision = nova.decision?.action || 'BLOCK';
const risk = nova.risk_score ?? 'n/a';
const reason = nova.decision?.reason || 'Nova no aprobó esta acción.';
let message = '🛡️ *Nova detuvo el envío*\n\n';
message += `📧 Para: ${architectData.to}\n`;
message += `📌 Asunto: ${architectData.subject || '(sin asunto)'}\n`;
message += `⚖️ Decisión: ${decision}\n`;
message += `📊 Riesgo: ${risk}\n`;
message += `🧠 Motivo: ${reason}`;
return [{
  json: {
    action: 'governance_blocked',
    success: false,
    message,
    data: {
      to: architectData.to,
      subject: architectData.subject,
      nova,
    },
    originalQuery: architectData.originalQuery,
  },
}];
